pragma solidity ^0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    mapping(address => uint256) public balances;

    event Bought(address indexed buyer, uint256 amount);
    event PriceChanged(uint256 newPrice);
    event Withdrawn(address indexed receiver, uint256 amount);

    bool private withdrawLock;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier nonReentrantWithdraw() {
        require(!withdrawLock, "Withdraw: reentrant call");
        withdrawLock = true;
        _;
        withdrawLock = false;
    }

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
    }

    function buy(uint256 amount) external payable {
        require(!saleEnded, "Sale has ended");
        require(amount > 0 && amount <= 10, "Invalid amount");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");

        uint256 totalCost = amount * price;
        require(msg.value >= totalCost, "Insufficient payment");

        totalMinted += amount;
        balances[msg.sender] += amount;

        if (msg.value > totalCost) {
            payable(msg.sender).transfer(msg.value - totalCost);
        }

        emit Bought(msg.sender, amount);

        if (totalMinted >= maxSupply) {
            saleEnded = true;
        }
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function withdraw() external nonReentrantWithdraw onlyOwner {
        uint256 balance = address(this).balance;
        payable(owner).transfer(balance);
        emit Withdrawn(owner, balance);
    }
}
